<svg viewBox="0 0 700 340" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="34" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">韓国Google Play — 仮想資産取引所アプリのアクセス状況(7月10日時点)</text>
  <g font-family="sans-serif">
    <rect x="20" y="60" width="300" height="90" rx="8" fill="#052e2b" stroke="#06b6d4" stroke-width="1.5"/>
    <text x="170" y="90" fill="#5eead4" font-size="15" font-weight="700" text-anchor="middle">FIU登録済み</text>
    <text x="170" y="118" fill="#fafafa" font-size="24" font-weight="700" text-anchor="middle">27プラットフォーム</text>
    <text x="170" y="138" fill="#a1a1aa" font-size="13" text-anchor="middle">Upbit・Bithumbなど国内取引所</text>
    <rect x="380" y="60" width="300" height="90" rx="8" fill="#3f1d1d" stroke="#f87171" stroke-width="1.5"/>
